/**
 * @guilherme/agent-sdk/errors
 *
 * Custom error types for the SDK.
 */

/**
 * Base error class for all SDK errors
 */
export class AgentSDKError extends Error {
  constructor(
    public readonly type: string,
    message: string,
    public readonly cause?: Error
  ) {
    super(message);
    this.name = 'AgentSDKError';
  }
}

/**
 * API returned an error response
 */
export class APIError extends AgentSDKError {
  constructor(
    public readonly statusCode: number,
    message: string,
    public readonly responseBody?: string
  ) {
    super('api_error', `API Error (${statusCode}): ${message}`);
    this.name = 'APIError';
  }

  get isRateLimited() {
    return this.statusCode === 429;
  }

  get isBadRequest() {
    return this.statusCode >= 400 && this.statusCode < 500;
  }

  get isServerError() {
    return this.statusCode >= 500;
  }
}

/**
 * Tool execution failed
 */
export class ToolExecutionError extends AgentSDKError {
  constructor(
    public readonly toolName: string,
    message: string,
    public readonly args?: any,
    cause?: Error
  ) {
    super('tool_execution_error', `Tool '${toolName}' failed: ${message}`, cause);
    this.name = 'ToolExecutionError';
  }
}

/**
 * Validation failed (Zod or schema)
 */
export class ValidationError extends AgentSDKError {
  constructor(
    message: string,
    public readonly issues: Array<{ path: string; message: string }>
  ) {
    super('validation_error', message);
    this.name = 'ValidationError';
  }
}

/**
 * Stream was aborted or interrupted
 */
export class StreamAbortError extends AgentSDKError {
  constructor(message: string = 'Stream was aborted') {
    super('stream_abort_error', message);
    this.name = 'StreamAbortError';
  }
}

/**
 * Max iterations reached without final response
 */
export class MaxIterationsError extends AgentSDKError {
  constructor(
    public readonly iterations: number,
    public readonly partialResult?: { content: string; toolCalls: any[] }
  ) {
    super('max_iterations_error', `Reached max iterations (${iterations}) without final response`);
    this.name = 'MaxIterationsError';
  }
}
