/**
 * @guilherme/agent-sdk/streamText
 *
 * Streaming text generation.
 */

import { ProviderConfig } from './AgentRuntime';
import { APIError, StreamAbortError } from './errors';

export interface StreamTextOptions {
  provider: ProviderConfig;
  prompt: string;
  systemPrompt?: string;
  temperature?: number;
  maxTokens?: number;
  /** Abort signal for cancellation */
  signal?: AbortSignal;
  /** Throttle callback invocations (ms) */
  throttle?: number;
}

export interface StreamTextResult {
  /** The full text content (updates during streaming) */
  content: string;
  /** Async iterator for streaming */
  stream: AsyncIterable<string>;
  /** Promise that resolves when streaming is done */
  done: Promise<void>;
  /** Abort the stream */
  abort: () => void;
}

/**
 * Stream text generation
 *
 * @example
 * ```ts
 * const result = streamText({
 *   provider: { baseUrl: '...', apiKey: '...', model: 'gpt-4' },
 *   prompt: 'Tell me a story',
 * });
 *
 * for await (const chunk of result.stream) {
 *   console.log(chunk);
 * }
 *
 * console.log('Full content:', result.content);
 * ```
 */
export function streamText(options: StreamTextOptions): StreamTextResult {
  const { provider, prompt, systemPrompt, temperature = 0.7, maxTokens, signal, throttle } = options;

  let fullContent = '';
  let aborted = false;
  let streamStarted = false;
  const controller = new AbortController();
  const combinedSignal = combineSignals(signal, controller.signal);

  const messages = [
    ...(systemPrompt ? [{ role: 'system' as const, content: systemPrompt }] : []),
    { role: 'user' as const, content: prompt },
  ];

  // Create a promise that will be resolved when streaming is complete
  let resolveDone: () => void;
  let rejectDone: (error: Error) => void;
  const donePromise = new Promise<void>((resolve, reject) => {
    resolveDone = resolve;
    rejectDone = reject;
  });

  async function* streamGenerator(): AsyncIterable<string> {
    if (streamStarted) {
      throw new Error('Stream can only be consumed once');
    }
    streamStarted = true;

    try {
      const response = await fetch(`${provider.baseUrl}/chat/completions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${provider.apiKey}`,
          ...provider.headers,
        },
        body: JSON.stringify({
          model: provider.model,
          messages,
          temperature,
          max_tokens: maxTokens,
          stream: true,
        }),
        signal: combinedSignal,
      });

      if (!response.ok) {
        const body = await response.text();
        throw new APIError(response.status, body, body);
      }

      const reader = response.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = '';
      let lastEmitTime = 0;
      let pendingChunk = '';

      const maybeEmit = (): string | null => {
        if (pendingChunk && (!throttle || Date.now() - lastEmitTime >= throttle)) {
          fullContent += pendingChunk;
          const chunk = pendingChunk;
          pendingChunk = '';
          lastEmitTime = Date.now();
          return chunk;
        }
        return null;
      };

      try {
        while (!aborted) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() ?? '';

          for (const line of lines) {
            if (!line.startsWith('data: ')) continue;
            const raw = line.slice(6).trim();
            if (raw === '[DONE]') {
              // Emit any remaining chunk
              if (pendingChunk) {
                fullContent += pendingChunk;
                yield pendingChunk;
              }
              return;
            }

            try {
              const parsed = JSON.parse(raw);
              const delta = parsed.choices?.[0]?.delta;
              if (delta?.content) {
                pendingChunk += delta.content;
                const chunk = maybeEmit();
                if (chunk) yield chunk;
              }
            } catch {
              // Ignore parse errors
            }
          }
        }

        // Emit final chunk if throttled
        if (pendingChunk) {
          fullContent += pendingChunk;
          yield pendingChunk;
        }

        if (aborted) {
          throw new StreamAbortError();
        }
      } finally {
        reader.releaseLock();
      }
    } catch (error) {
      rejectDone(error instanceof Error ? error : new Error(String(error)));
      throw error;
    }
  }

  // Wrap the generator to resolve done when complete
  async function* wrappedStream(): AsyncIterable<string> {
    try {
      for await (const chunk of streamGenerator()) {
        yield chunk;
      }
      resolveDone();
    } catch (error) {
      rejectDone(error instanceof Error ? error : new Error(String(error)));
      throw error;
    }
  }

  return {
    get content() { return fullContent; },
    stream: wrappedStream(),
    done: donePromise,
    abort: () => {
      aborted = true;
      controller.abort();
    },
  };
}

function combineSignals(signal1?: AbortSignal, signal2?: AbortSignal): AbortSignal | undefined {
  if (!signal1 && !signal2) return undefined;
  if (!signal1) return signal2;
  if (!signal2) return signal1;

  const controller = new AbortController();
  const abort = () => controller.abort();

  signal1.addEventListener('abort', abort);
  signal2.addEventListener('abort', abort);

  return controller.signal;
}
