/**
 * @guilherme/agent-sdk/generateText
 *
 * Simple text generation without streaming.
 */

import { ProviderConfig } from './AgentRuntime';
import { APIError } from './errors';

export interface GenerateTextOptions {
  provider: ProviderConfig;
  prompt: string;
  systemPrompt?: string;
  temperature?: number;
  maxTokens?: number;
  /** Abort signal for cancellation */
  signal?: AbortSignal;
}

export interface GenerateTextResult {
  content: string;
  usage?: {
    promptTokens: number;
    completionTokens: number;
    totalTokens: number;
  };
  finishReason: 'stop' | 'length' | 'content_filter' | 'unknown';
}

/**
 * Generate text without streaming
 *
 * @example
 * ```ts
 * const result = await generateText({
 *   provider: { baseUrl: '...', apiKey: '...', model: 'gpt-4' },
 *   prompt: 'Write a haiku about coding',
 * });
 * console.log(result.content);
 * ```
 */
export async function generateText(options: GenerateTextOptions): Promise<GenerateTextResult> {
  const { provider, prompt, systemPrompt, temperature = 0.7, maxTokens, signal } = options;

  const messages = [
    ...(systemPrompt ? [{ role: 'system' as const, content: systemPrompt }] : []),
    { role: 'user' as const, content: prompt },
  ];

  const response = await fetch(`${provider.baseUrl}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${provider.apiKey}`,
      ...provider.headers,
    },
    body: JSON.stringify({
      model: provider.model,
      messages,
      temperature,
      max_tokens: maxTokens,
      stream: false,
    }),
    signal,
  });

  if (!response.ok) {
    const body = await response.text();
    throw new APIError(response.status, body, body);
  }

  const data = await response.json();
  const choice = data.choices[0];

  return {
    content: choice.message.content || '',
    usage: data.usage ? {
      promptTokens: data.usage.prompt_tokens,
      completionTokens: data.usage.completion_tokens,
      totalTokens: data.usage.total_tokens,
    } : undefined,
    finishReason: choice.finish_reason || 'unknown',
  };
}
