/**
 * HistoryStore - Interface para armazenamento de histórico
 *
 * Implementações: memory, Redis, PostgreSQL
 */

import { ChatMessage } from './AgentRuntime';

export interface HistoryStore {
  get(sessionId: string): Promise<ChatMessage[]>;
  set(sessionId: string, messages: ChatMessage[]): Promise<void>;
  clear(sessionId: string): Promise<void>;
}

/**
 * Memory-based history store (default)
 *
 * Em produção, usar Redis ou database.
 */
export function memoryStore(): HistoryStore {
  const store = new Map<string, ChatMessage[]>();

  return {
    async get(sessionId: string) {
      return store.get(sessionId) ?? [];
    },

    async set(sessionId: string, messages: ChatMessage[]) {
      store.set(sessionId, messages);
    },

    async clear(sessionId: string) {
      store.delete(sessionId);
    },
  };
}

/**
 * Redis-like client interface (works with @upstash/redis and ioredis)
 */
export interface RedisLike {
  get(key: string): Promise<string | null | undefined>;
  set(key: string, value: string, options?: { ex?: number }): Promise<unknown>;
  del(key: string): Promise<unknown>;
}

/**
 * Redis-based history store
 *
 * Works with @upstash/redis, ioredis, or any Redis client that implements RedisLike.
 *
 * @example
 * ```ts
 * import { Redis } from '@upstash/redis';
 * import { redisStore } from '@guilherme/agent-sdk';
 *
 * const redis = new Redis({
 *   url: process.env.UPSTASH_REDIS_REST_URL!,
 *   token: process.env.UPSTASH_REDIS_REST_TOKEN!,
 * });
 *
 * export const POST = createAgentRoute({
 *   historyStore: redisStore(redis),
 *   // ...
 * });
 * ```
 */
export function redisStore(
  redis: RedisLike,
  options: {
    /** Key prefix (default: 'agent:history:') */
    prefix?: string;
    /** TTL in seconds (default: 7 days) */
    ttl?: number;
  } = {}
): HistoryStore {
  const { prefix = 'agent:history:', ttl = 86400 * 7 } = options;

  return {
    async get(sessionId: string) {
      const data = await redis.get(`${prefix}${sessionId}`);
      if (!data) return [];
      try {
        return JSON.parse(data as string) as ChatMessage[];
      } catch {
        return [];
      }
    },

    async set(sessionId: string, messages: ChatMessage[]) {
      await redis.set(`${prefix}${sessionId}`, JSON.stringify(messages), {
        ex: ttl,
      });
    },

    async clear(sessionId: string) {
      await redis.del(`${prefix}${sessionId}`);
    },
  };
}

/**
 * PostgreSQL pool interface (works with pg)
 */
export interface PostgresPool {
  query<T = any>(sql: string, params?: any[]): Promise<{ rows: T[] }>;
}

/**
 * PostgreSQL-based history store
 *
 * Requires a `agent_sessions` table:
 * ```sql
 * CREATE TABLE agent_sessions (
 *   id TEXT PRIMARY KEY,
 *   messages JSONB NOT NULL DEFAULT '[]',
 *   created_at TIMESTAMPTZ DEFAULT NOW(),
 *   updated_at TIMESTAMPTZ DEFAULT NOW()
 * );
 * ```
 *
 * @example
 * ```ts
 * import { Pool } from 'pg';
 * import { postgresStore } from '@guilherme/agent-sdk';
 *
 * const pool = new Pool({ connectionString: process.env.DATABASE_URL });
 *
 * export const POST = createAgentRoute({
 *   historyStore: postgresStore(pool),
 *   // ...
 * });
 * ```
 */
export function postgresStore(pool: PostgresPool): HistoryStore {
  return {
    async get(sessionId: string) {
      const result = await pool.query<{ messages: ChatMessage[] }>(
        'SELECT messages FROM agent_sessions WHERE id = $1',
        [sessionId]
      );
      return result.rows[0]?.messages || [];
    },

    async set(sessionId: string, messages: ChatMessage[]) {
      // Auto-generate title from first user message
      const firstUserMsg = messages.find(m => m.role === 'user');
      const title = firstUserMsg?.content?.slice(0, 80) || null;

      await pool.query(
        `INSERT INTO agent_sessions (id, messages, title, updated_at)
         VALUES ($1, $2, $3, NOW())
         ON CONFLICT (id) DO UPDATE SET messages = $2, updated_at = NOW()`,
        [sessionId, JSON.stringify(messages), title]
      );
    },

    async clear(sessionId: string) {
      await pool.query('DELETE FROM agent_sessions WHERE id = $1', [sessionId]);
    },
  };
}

/**
 * Session metadata for listing/management
 */
export interface SessionMetadata {
  id: string;
  title?: string;
  createdAt: string;
  updatedAt: string;
  messageCount: number;
}

/**
 * Session store interface for managing chat sessions
 */
export interface SessionStore {
  list(userId: string, tenantId: string, options?: { limit?: number; offset?: number }): Promise<{ sessions: SessionMetadata[]; total: number }>;
  updateTitle(sessionId: string, title: string): Promise<void>;
  deleteSession(sessionId: string): Promise<void>;
}

/**
 * PostgreSQL-based session store for listing/managing sessions
 *
 * Requires the agent_sessions table to have title, user_id, tenant_id columns.
 */
export function postgresSessionStore(pool: PostgresPool): SessionStore {
  return {
    async list(userId: string, tenantId: string, options?: { limit?: number; offset?: number }) {
      const limit = options?.limit || 30;
      const offset = options?.offset || 0;

      const result = await pool.query<SessionMetadata>(
        `SELECT id, title, created_at, updated_at, jsonb_array_length(messages) as message_count
         FROM agent_sessions
         WHERE user_id = $1 AND tenant_id = $2
         ORDER BY updated_at DESC
         LIMIT $3 OFFSET $4`,
        [userId, tenantId, limit, offset]
      );

      const countResult = await pool.query(
        `SELECT COUNT(*)::int as total FROM agent_sessions WHERE user_id = $1 AND tenant_id = $2`,
        [userId, tenantId]
      );

      return {
        sessions: result.rows,
        total: countResult.rows[0]?.total || 0,
      };
    },

    async updateTitle(sessionId: string, title: string) {
      await pool.query(
        'UPDATE agent_sessions SET title = $1, updated_at = NOW() WHERE id = $2',
        [title, sessionId]
      );
    },

    async deleteSession(sessionId: string) {
      await pool.query('DELETE FROM agent_sessions WHERE id = $1', [sessionId]);
    },
  };
}

/**
 * SQLite database interface (works with better-sqlite3, bun:sqlite)
 */
export interface SQLiteDatabase {
  prepare(sql: string): {
    get<T = any>(params: any[]): T | undefined;
    run(params: any[]): { changes: number };
  };
}

/**
 * SQLite-based history store
 *
 * Requires a `agent_sessions` table:
 * ```sql
 * CREATE TABLE IF NOT EXISTS agent_sessions (
 *   id TEXT PRIMARY KEY,
 *   messages TEXT NOT NULL DEFAULT '[]',
 *   updated_at TEXT DEFAULT CURRENT_TIMESTAMP
 * );
 * ```
 *
 * @example
 * ```ts
 * import Database from 'better-sqlite3';
 * import { sqliteStore } from '@guilherme/agent-sdk';
 *
 * const db = new Database('sessions.db');
 * db.exec(`CREATE TABLE IF NOT EXISTS agent_sessions ...`);
 *
 * export const POST = createAgentRoute({
 *   historyStore: sqliteStore(db),
 *   // ...
 * });
 * ```
 */
export function sqliteStore(db: SQLiteDatabase): HistoryStore {
  return {
    async get(sessionId: string) {
      const stmt = db.prepare('SELECT messages FROM agent_sessions WHERE id = ?');
      const row = stmt.get<{ messages: string }>([sessionId]) as
        | { messages: string }
        | undefined;
      if (!row) return [];
      try {
        return JSON.parse(row.messages) as ChatMessage[];
      } catch {
        return [];
      }
    },

    async set(sessionId: string, messages: ChatMessage[]) {
      const stmt = db.prepare(`
        INSERT INTO agent_sessions (id, messages, updated_at)
        VALUES (?, ?, datetime('now'))
        ON CONFLICT(id) DO UPDATE SET messages = excluded.messages, updated_at = excluded.updated_at
      `);
      stmt.run([sessionId, JSON.stringify(messages)]);
    },

    async clear(sessionId: string) {
      const stmt = db.prepare('DELETE FROM agent_sessions WHERE id = ?');
      stmt.run([sessionId]);
    },
  };
}

/**
 * File-based history store (for development/simple deployments)
 *
 * Stores each session as a JSON file in a directory.
 *
 * @example
 * ```ts
 * import { fileStore } from '@guilherme/agent-sdk';
 *
 * export const POST = createAgentRoute({
 *   historyStore: fileStore('./data/sessions'),
 *   // ...
 * });
 * ```
 */
export function fileStore(
  dir: string,
  options: {
    /** File extension (default: '.json') */
    extension?: string;
  } = {}
): HistoryStore {
  const { extension = '.json' } = options;
  const fs = require('fs');
  const path = require('path');

  // Ensure directory exists
  try {
    fs.mkdirSync(dir, { recursive: true });
  } catch {
    // Directory already exists
  }

  const getFilePath = (sessionId: string) =>
    path.join(dir, `${sessionId}${extension}`);

  return {
    async get(sessionId: string) {
      try {
        const data = fs.readFileSync(getFilePath(sessionId), 'utf-8');
        return JSON.parse(data) as ChatMessage[];
      } catch {
        return [];
      }
    },

    async set(sessionId: string, messages: ChatMessage[]) {
      fs.writeFileSync(getFilePath(sessionId), JSON.stringify(messages, null, 2));
    },

    async clear(sessionId: string) {
      try {
        fs.unlinkSync(getFilePath(sessionId));
      } catch {
        // File doesn't exist
      }
    },
  };
}
