/**
 * defineTool - Define uma tool com Zod schema ou JSON Schema
 * 
 * Abstrai a conversão de Zod para JSON Schema automaticamente.
 */

import { z } from 'zod';

export interface ZodSchemaLike<TOutput = any> {
  description?: string;
  parse: (input: unknown) => TOutput;
  safeParse: (input: unknown) =>
    | { success: true; data: TOutput }
    | {
        success: false;
        error: {
          issues: Array<{
            path: PropertyKey[];
            message: string;
          }>;
        };
      };
  _def?: unknown;
  _output?: TOutput;
}

type InferSchemaOutput<TSchema extends ZodSchemaLike<any>> =
  TSchema extends { _output?: infer TOutput }
    ? TOutput
    : TSchema extends { parse: (input: unknown) => infer TOutput }
      ? TOutput
      : never;

interface ToolDefinitionBase<TInput, TOutput> {
  name: string;
  description: string;
  execute: (args: TInput) => Promise<TOutput> | TOutput;
  /** Se true, exige confirmação do usuário antes de executar */
  awaitConfirm?: boolean;
  /** Mensagem de confirmação customizada (args → string) */
  confirmMessage?: (args: TInput) => string;
  /** Tools que esta tool depende (outputs necessários) */
  dependencies?: string[];
  /** Se true, pode rodar em paralelo com outras (default: true se sem dependências) */
  parallelizable?: boolean;
}

export interface JsonSchemaToolDefinition<TInput = any, TOutput = any>
  extends ToolDefinitionBase<TInput, TOutput> {
  parameters: JSONSchema;
}

export interface ZodToolDefinition<TSchema extends ZodSchemaLike<any>, TOutput = any>
  extends ToolDefinitionBase<InferSchemaOutput<TSchema>, TOutput> {
  parameters: TSchema;
}

export type ToolDefinition<TInput = any, TOutput = any> =
  | JsonSchemaToolDefinition<TInput, TOutput>
  | ZodToolDefinition<ZodSchemaLike<TInput>, TOutput>;

export interface JSONSchema {
  type: 'object';
  properties?: Record<string, any>;
  required?: string[];
  [key: string]: any;
}

/**
 * Converte Zod schema para JSON Schema (OpenAI-compatible)
 *
 * Simplificado - suporta tipos básicos. Para casos complexos, passe JSON Schema direto.
 */
export function zodToJsonSchema(zodType: ZodSchemaLike<any>): JSONSchema {
  const schema: JSONSchema = { type: 'object', properties: {}, required: [] };

  if (zodType instanceof z.ZodObject) {
    const shape = zodType.shape;
    
    for (const [key, value] of Object.entries(shape)) {
      const propSchema = zodFieldToJsonSchema(value as z.ZodTypeAny);
      schema.properties![key] = propSchema.schema;
      if (!propSchema.optional) {
        schema.required!.push(key);
      }
    }
  }

  if (schema.required!.length === 0) {
    delete schema.required;
  }

  return schema;
}

function zodFieldToJsonSchema(zodType: z.ZodTypeAny): { schema: any; optional: boolean } {
  // Optional
  if (zodType instanceof z.ZodOptional) {
    const inner = zodFieldToJsonSchema(zodType.unwrap());
    return { schema: inner.schema, optional: true };
  }

  // Nullable
  if (zodType instanceof z.ZodNullable) {
    const inner = zodFieldToJsonSchema(zodType.unwrap());
    return { schema: { ...inner.schema, nullable: true }, optional: inner.optional };
  }

  // Default
  if (zodType instanceof z.ZodDefault) {
    const inner = zodFieldToJsonSchema(zodType.removeDefault());
    return { schema: inner.schema, optional: true };
  }

  // String
  if (zodType instanceof z.ZodString) {
    return {
      schema: {
        type: 'string',
        description: zodType.description || undefined,
      },
      optional: false,
    };
  }

  // Number
  if (zodType instanceof z.ZodNumber) {
    return {
      schema: {
        type: 'number',
        description: zodType.description || undefined,
      },
      optional: false,
    };
  }

  // Boolean
  if (zodType instanceof z.ZodBoolean) {
    return {
      schema: {
        type: 'boolean',
        description: zodType.description || undefined,
      },
      optional: false,
    };
  }

  // Array
  if (zodType instanceof z.ZodArray) {
    const elementType = zodFieldToJsonSchema(zodType.element);
    return {
      schema: {
        type: 'array',
        items: elementType.schema,
        description: zodType.description || undefined,
      },
      optional: false,
    };
  }

  // Enum
  if (zodType instanceof z.ZodEnum) {
    return {
      schema: {
        type: 'string',
        enum: zodType.options,
        description: zodType.description || undefined,
      },
      optional: false,
    };
  }

  // Literal
  if (zodType instanceof z.ZodLiteral) {
    return {
      schema: { const: zodType.value },
      optional: false,
    };
  }

  // Union
  if (zodType instanceof z.ZodUnion) {
    const anyOf = zodType.options.map((opt: z.ZodTypeAny) => zodFieldToJsonSchema(opt).schema);
    return {
      schema: { anyOf, description: zodType.description || undefined },
      optional: false,
    };
  }

  // Record (objetos com chaves dinâmicas)
  if (zodType instanceof z.ZodRecord) {
    const valueType = zodFieldToJsonSchema(zodType.valueSchema);
    return {
      schema: {
        type: 'object',
        additionalProperties: valueType.schema,
        description: zodType.description || undefined,
      },
      optional: false,
    };
  }

  // Object (nested)
  if (zodType instanceof z.ZodObject) {
    const nestedSchema: JSONSchema = { type: 'object', properties: {}, required: [] };
    const shape = zodType.shape;

    for (const [key, value] of Object.entries(shape)) {
      const propSchema = zodFieldToJsonSchema(value as z.ZodTypeAny);
      nestedSchema.properties![key] = propSchema.schema;
      if (!propSchema.optional) {
        nestedSchema.required!.push(key);
      }
    }

    if (nestedSchema.required!.length === 0) {
      delete nestedSchema.required;
    }

    return {
      schema: { ...nestedSchema, description: zodType.description || undefined },
      optional: false,
    };
  }

  // Default fallback
  return {
    schema: {
      type: 'object',
      description: zodType.description || undefined,
    },
    optional: false,
  };
}

/**
 * Define uma tool com tipagem automática via Zod
 * 
 * @example
 * ```ts
 * const myTool = defineTool({
 *   name: 'create_product',
 *   description: 'Cria um produto',
 *   parameters: z.object({
 *     name: z.string().describe('Nome do produto'),
 *     price: z.number().describe('Preço em reais'),
 *   }),
 *   execute: async (args) => {
 *     // args é tipado: { name: string; price: number }
 *     return await db.product.create({ data: args });
 *   },
 * });
 * ```
 */
export function defineTool<TSchema extends ZodSchemaLike<any>, TOutput>(
  definition: ZodToolDefinition<TSchema, TOutput>
): RuntimeTool<InferSchemaOutput<TSchema>, TOutput>;
export function defineTool<TInput, TOutput>(
  definition: JsonSchemaToolDefinition<TInput, TOutput>
): RuntimeTool<TInput, TOutput>;
export function defineTool<TInput, TOutput>(
  definition: ToolDefinition<TInput, TOutput>
): RuntimeTool<TInput, TOutput> {
  const params = definition.parameters;

  if (isZodType(params)) {
    return {
      name: definition.name,
      description: definition.description,
      parameters: zodToJsonSchema(params),
      zodSchema: params,
      execute: definition.execute,
      awaitConfirm: definition.awaitConfirm,
      confirmMessage: definition.confirmMessage,
      dependencies: definition.dependencies,
      parallelizable: definition.parallelizable,
    };
  }

  return {
    name: definition.name,
    description: definition.description,
    parameters: params as JSONSchema,
    zodSchema: undefined,
    execute: definition.execute,
    awaitConfirm: definition.awaitConfirm,
    confirmMessage: definition.confirmMessage,
    dependencies: definition.dependencies,
    parallelizable: definition.parallelizable,
  };
}

function isZodType(value: any): value is z.ZodTypeAny {
  return value && typeof value === 'object' && '_def' in value;
}

export interface RuntimeTool<TInput = any, TOutput = any> {
  name: string;
  description: string;
  parameters: JSONSchema;
  /** Schema Zod original para validação em runtime */
  zodSchema?: ZodSchemaLike<TInput>;
  execute: (args: TInput) => Promise<TOutput> | TOutput;
  awaitConfirm?: boolean;
  confirmMessage?: (args: TInput) => string;
  /** Tools que esta tool depende (outputs necessários) */
  dependencies?: string[];
  /** Se true, pode rodar em paralelo com outras (default: true se sem dependências) */
  parallelizable?: boolean;
}

/**
 * Converte RuntimeTool[] para o formato OpenAI-compatible
 */
export function toolsToOpenAIFormat(tools: RuntimeTool[]): any[] {
  return tools.map((tool) => ({
    type: 'function',
    function: {
      name: tool.name,
      description: tool.description,
      parameters: tool.parameters,
    },
  }));
}
